// ─── City × Product Combination Generator ────────────────────────────────────

export function generateCityProductCombinations(): CityProductCombination[] {
  const combos: CityProductCombination[] = [];
  for (const city of SEO_CITIES) {
    for (const product of SEO_PRODUCTS) {
      const matchingBrands = SEO_BRANDS.filter(
        (b) =>
          b.categories.some((cat) => cat.slug === product.categorySlug) ||
          b.productCategories.some(
            (pc) =>
              pc.toLowerCase().includes(product.category.toLowerCase().split(' ')[0])
          )
      ).map((b) => b.slug);

      combos.push({
        slug: `buy-${product.slug}-in-${city.slug}`,
        title: `Buy ${product.name} in ${city.name} | Best Price at Hub4Estate`,
        description: `Get the best price on ${product.name} in ${city.name}, ${city.state}. Compare dealer quotes, save up to ${product.savingsPercent} vs MRP. Verified dealers, fast delivery.`,
        h1: `Best ${product.name} Price in ${city.name}`,
        citySlug: city.slug,
        productSlug: product.slug,
        brandSlugs: matchingBrands.slice(0, 6),
      });
    }
  }
  return combos;
}

// ─── Lookup Functions ────────────────────────────────────────────────────────

export function getProductBySlug(slug: string): SEOProduct | undefined {
  return SEO_PRODUCTS.find((p) => p.slug === slug);
}

export function getBrandBySlug(slug: string): SEOBrand | undefined {
  return SEO_BRANDS.find((b) => b.slug === slug);
}

export function getCityBySlug(slug: string): SEOCity | undefined {
  return SEO_CITIES.find((c) => c.slug === slug);
}

export function getSchemeBySlug(slug: string): SEOGovernmentScheme | undefined {
  return SEO_GOVERNMENT_SCHEMES.find((s) => s.slug === slug);
}

// ─── Filter Functions ────────────────────────────────────────────────────────

export function getCitiesByState(state: string): SEOCity[] {
  return SEO_CITIES.filter((c) => c.state === state);
}

export function getCitiesByTier(tier: 1 | 2 | 3): SEOCity[] {
  return SEO_CITIES.filter((c) => c.tier === tier);
}

export function getProductsByCategory(categorySlug: string): SEOProduct[] {
  return SEO_PRODUCTS.filter((p) => p.categorySlug === categorySlug);
}

export function getBrandsByProductCategory(categorySlug: string): SEOBrand[] {
  return SEO_BRANDS.filter((b) =>
    b.categories.some((cat) => cat.slug === categorySlug)
  );
}

export function getSchemesByCategory(
  category: SEOGovernmentScheme['category']
): SEOGovernmentScheme[] {
  return SEO_GOVERNMENT_SCHEMES.filter((s) => s.category === category);
}

// ─── Search/Find Functions ───────────────────────────────────────────────────

export function findProduct(query: string): SEOProduct[] {
  const q = query.toLowerCase();
  return SEO_PRODUCTS.filter(
    (p) =>
      p.name.toLowerCase().includes(q) ||
      p.slug.includes(q) ||
      p.keywords.some((k) => k.includes(q)) ||
      p.category.toLowerCase().includes(q)
  );
}

export function findBrand(query: string): SEOBrand[] {
  const q = query.toLowerCase();
  return SEO_BRANDS.filter(
    (b) =>
      b.name.toLowerCase().includes(q) ||
      b.slug.includes(q) ||
      b.keywords.some((k) => k.includes(q))
  );
}

export function findCity(query: string): SEOCity[] {
  const q = query.toLowerCase();
  return SEO_CITIES.filter(
    (c) =>
      c.name.toLowerCase().includes(q) ||
      c.slug.includes(q) ||
      c.state.toLowerCase().includes(q) ||
      c.keywords.some((k) => k.includes(q))
  );
}

export function findScheme(query: string): SEOGovernmentScheme[] {
  const q = query.toLowerCase();
  return SEO_GOVERNMENT_SCHEMES.filter(
    (s) =>
      s.name.toLowerCase().includes(q) ||
      s.slug.includes(q) ||
      s.keywords.some((k) => k.includes(q)) ||
      s.shortDescription.toLowerCase().includes(q)
  );
}

