// ─── Stats & Aggregate Functions ─────────────────────────────────────────────

export function getTotalKeywordCount(): number {
  let count = 0;
  count += SEO_PRODUCTS.reduce((sum, p) => sum + p.keywords.length, 0);
  count += SEO_BRANDS.reduce((sum, b) => sum + b.keywords.length, 0);
  count += SEO_CITIES.reduce((sum, c) => sum + c.keywords.length, 0);
  count += SEO_GOVERNMENT_SCHEMES.reduce((sum, s) => sum + s.keywords.length, 0);
  count += Object.values(SEO_KEYWORD_CLUSTERS).reduce((sum, arr) => sum + arr.length, 0);
  return count;
}

export function getProductCategories(): string[] {
  return [...new Set(SEO_PRODUCTS.map((p) => p.category))];
}

export function getStates(): string[] {
  return [...new Set(SEO_CITIES.map((c) => c.state))].sort();
}

export function getCitiesGroupedByState(): Record<string, SEOCity[]> {
  const grouped: Record<string, SEOCity[]> = {};
  for (const city of SEO_CITIES) {
    if (!grouped[city.state]) grouped[city.state] = [];
    grouped[city.state].push(city);
  }
  return grouped;
}

export function getRajasthanCities(): SEOCity[] {
  return SEO_CITIES.filter((c) => c.state === 'Rajasthan');
}

export function getSEOStats() {
  const totalCombinations = SEO_CITIES.length * SEO_PRODUCTS.length;
  return {
    products: SEO_PRODUCTS.length,
    brands: SEO_BRANDS.length,
    cities: SEO_CITIES.length,
    schemes: SEO_GOVERNMENT_SCHEMES.length,
    keywordClusters: Object.keys(SEO_KEYWORD_CLUSTERS).length,
    totalKeywords: getTotalKeywordCount(),
    totalCityProductCombinations: totalCombinations,
    tier1Cities: SEO_CITIES.filter((c) => c.tier === 1).length,
    tier2Cities: SEO_CITIES.filter((c) => c.tier === 2).length,
    tier3Cities: SEO_CITIES.filter((c) => c.tier === 3).length,
    rajasthanCities: getRajasthanCities().length,
    states: getStates().length,
    productCategories: getProductCategories().length,
  };
}
